mapper.select:
select

from poi

    temporarily_closed = 0

        and name like concat('%', #{keyword}, '%')


        and (city_code = #{cityCode}
            or (city_code is null and (#{cityCode} = 'CD' or #{cityCode} = 'cd')))


        and (city_name = #{cityName}
            or (city_name is null and #{cityName} = '成都'))


order by priority_score desc, id desc
limit #{limit}
